const input = items[0].json;

// 1. Estrazione ID SVC
const callbackData = input.body.callback_query.data;
const svcId = callbackData.split('post_')[1]; 

// 2. Recupero dati servizio dal catalogo
let selectedService = null;
const categories = input.service_catalog_setup.categories || [];

for (const cat of categories) {
  const match = cat.subcategories.find(s => s.callback_data === svcId);
  if (match) {
    selectedService = {
      ...match,
      category_name: cat.name
    };
    break;
  }
}

// 3. Ritorno SOLO i blocchi richiesti + il servizio estratto
return {
  HoneyPot: input.HoneyPot,
  owner_data: input.owner_data,
  body: input.body,
  selected_service: selectedService
};

const item = $input.first().json;
const owner = item.owner_data || {};

// Recuperiamo l'immagine. Usiamo gallery1, se non c'è usiamo photo, se non c'è usiamo logo
const assets = item.HoneyPot?.assets || {};
const photoUrl = (assets.gallery1 && assets.gallery1.url) || 
                 (assets.photo && assets.photo.url) || 
                 (assets.logo && assets.logo.url);

// Costruiamo il payload per INVIARE LA FOTO
return [{ 
    json: { 
        ...item, 
        telegramApiPayload: {
            method: "sendDocument", 
            chat_id: owner.chat_id, 
            photo: photoUrl
            // Non mettiamo caption per evitare limiti di caratteri
        }
    }
}];

